if(gN>0){for(var v=0;v<hp.length;v++){var ch=hp[v];if(ch.levelBuy>C.LEVNA||sO[ch.offset])continue;
var ec=ch.buy/C.rtEff+C.amort;if(ec<avgE||avgE===0||mnt)viab.push(ch);}viab.sort(function(a,b){return a.buy-b.buy;});}
var hN=Math.ceil(gN/C.chKwh);
for(var ci=0;ci<viab.length&&asgn<hN;ci++){cO[viab[ci].offset]=true;asgn++;}
// KROK 7: discharge
var cands=[],dO={},effT=C.DRAHA,uKwh=0,bgt=Math.max(0,(x.cSoc-C.minSoc)/100*C.kap*C.dchEff);
for(var dc=0;dc<hp.length;dc++)if(!sO[dc]&&!cO[dc])cands.push({offset:dc,hour:hp[dc].hour,levelBuy:hp[dc].levelBuy,buy:hp[dc].buy});
cands.sort(function(a,b){return b.buy-a.buy;});
for(var di=0;di<cands.length;di++){var c=cands[di],ek=C.socN/100*C.kap;
if(uKwh+ek<=bgt){dO[c.offset]=true;uKwh+=ek;effT=Math.min(effT,c.levelBuy);}
else if(c.levelBuy>=C.DRAHA&&uKwh<bgt){dO[c.offset]=true;uKwh=bgt;effT=Math.min(effT,c.levelBuy);}}
var bEx=false;for(var be=0;be<cands.length;be++)if(!dO[cands[be].offset]&&cands[be].levelBuy>=C.DRAHA){bEx=true;break;}
var sGT=0;if(sC>0){for(var sg=0;sg<C.hor;sg++){if(!sO[sg])continue;var sgh=(x.cH+sg)%24,sgK=x.fPH[sgh]||0,sgC=C.dayCons/24;sGT+=Math.max(0,(sgK-sgC)*C.chEff/C.kap)*100;}}
x.hp=hp;x.sO=sO;x.sC=sC;x.cO=cO;x.dO=dO;x.effT=effT;x.bEx=bEx;x.viab=viab;x.tSoc=tSoc;x.gN=gN;x.mnt=mnt;
x.bgt=bgt;x.uKwh=uKwh;x.avgE=avgE;x.sGT=sGT;x.drB=drB;x.sAD=sAD;x.minR=minR;x.fSol=fSol;x.asgn=asgn;x.hN=hN;
node.status({fill:"blue",shape:"dot",text:"Cena dch:"+Object.keys(dO).length+" ch:"+asgn+" effT:"+effT});
return msg;

// [3/5] Arbitráž + trimming (KROK 7b+7c)
var x=msg.ctx, C=x.C, hp=x.hp, pr=x.prices;
var aCO={},aSO={};
// Extended prices 36h
var ext=[];for(var i=0;i<36;i++){var eh=(x.cH+i)%24,e=x.fP(eh,i);if(e)ext.push({offset:i,hour:eh,buy:e.priceCZKhourBuy||0,sell:e.priceCZKhourProd||0,levelBuy:e.levelCheapestHourBuy||99});}
var pSoc=Math.min(100,x.cSoc+x.sGT);
var extE=ext.filter(function(h){return h.buy>0;}).sort(function(a,b){return b.buy-a.buy;});
var cheap=hp.slice().filter(function(h){return !x.sO[h.offset]&&!x.cO[h.offset];}).sort(function(a,b){return a.buy-b.buy;});
var mtch={},tAK=0,mxA=Math.max(0,((100-C.nResPct)-Math.max(x.cSoc,pSoc))/100*C.kap);
for(var ai=0;ai<cheap.length&&tAK<mxA;ai++){var ch=cheap[ai],ec=ch.buy/C.rtEff+C.amort;
for(var ei=0;ei<extE.length;ei++){var ex=extE[ei];if(mtch[ex.offset]||ex.offset<=ch.offset)continue;
var sp=ex.buy-ch.buy,pf=ex.buy-ec;if(sp<C.minArb||pf<=0)continue;
aCO[ch.offset]={targetHour:ex.hour,rawSpread:Math.round(sp*100)/100,effProfit:Math.round(pf*100)/100};
mtch[ex.offset]=true;tAK+=C.chKwh;
if(ex.offset<C.hor&&C.prodej){var ss=ex.sell-ch.buy,sf=ex.sell*C.dchEff-ec;
if(ss>=C.minSell&&sf>0)aSO[ex.offset]={rawSpread:Math.round(ss*100)/100};}break;}}
// KROK 7c: Trim
var aS={},dO=x.dO;
for(var ar in aCO)delete dO[ar];
for(var p=0;p<hp.length;p++){var ph=hp[p];if(ph.levelBuy>=C.DRAHA&&!dO[ph.offset]&&!x.sO[ph.offset]&&!x.cO[ph.offset]&&!aCO[ph.offset])dO[ph.offset]=true;}
var dK=Object.keys(dO).map(Number);
dK.sort(function(a,b){var pA=0,pB=0;for(var i=0;i<hp.length;i++){if(hp[i].offset===a)pA=hp[i].buy;if(hp[i].offset===b)pB=hp[i].buy;}return pA-pB;});
var tE=C.minSoc+C.nMargin, tD=dK.length*C.socN, pE=x.cSoc-tD;
while(pE<tE&&dK.length>0){var nO=dK[0],nL=0;for(var n=0;n<hp.length;n++)if(hp[n].offset===nO){nL=hp[n].levelBuy;break;}
if(nL>=C.DRAHA){dK.shift();continue;}var tr=dK.shift();delete dO[tr];aS[tr]=true;tD-=C.socN;pE=x.cSoc-tD;}
// Fill
var fl=[];for(var fi=0;fi<hp.length;fi++){var fh=hp[fi];if(!dO[fh.offset]&&!x.sO[fh.offset]&&!x.cO[fh.offset]&&!aCO[fh.offset]&&!aS[fh.offset])fl.push(fh);}
fl.sort(function(a,b){return b.buy-a.buy;});
for(var ff=0;ff<fl.length;ff++){if(pE-C.socN>=tE){dO[fl[ff].offset]=true;tD+=C.socN;pE=x.cSoc-tD;}}
if(Object.keys(aCO).length>0){var at=Math.min(100,x.cSoc+((tAK*C.chEff)/C.kap*100));x.tSoc=Math.max(x.tSoc,at);}
x.dO=dO;x.aCO=aCO;x.aSO=aSO;x.aS=aS;x.tAK=tAK;x.pSoc=pSoc;
node.status({fill:"blue",shape:"dot",text:"Arb ch:"+Object.keys(aCO).length+" trim:"+Object.keys(aS).length});
return msg;

// [4/5] Generování plánu (KROK 8 — calculateMode + simulateSoc)
var x=msg.ctx, C=x.C, hp=x.hp, M=x.MODY;
function gP(h){for(var i=0;i<x.cPred.length;i++)if(x.cPred[i].hour===h)return x.cPred[i];return null;}
function sS(h){return(x.cw[h]||0)/x.tW;}
function sG(h,f){f=f||1;var p=gP(h),c=(p&&p.avgConsumptionKwh>0)?p.avgConsumptionKwh:C.dayCons/24;
if(c>C.dayCons/6)c=C.dayCons/6;
var iS=h>=x.solS&&h<x.solE;if(iS&&x.nibeK>0&&(x.fPH[h]||0)>C.solOverKwh)c+=x.nibeK;
if(x.fPH[h]!==undefined)return((x.fPH[h]-c*f)*f*C.chEff/C.kap)*100;
if(p&&p.sampleCount>=3&&p.avgSolarKwh>0)return((p.netSolarGainKwh||0)*f*C.chEff/C.kap)*100;
if(x.sC>0&&x.rS>0){var hk=x.rS*sS(h);return((hk-c*f)*f*C.chEff/C.kap)*100;}
if(x.fZ>0&&sS(h)>0){var fk=x.fZ*sS(h);return((fk-c*f)*f*C.chEff/C.kap)*100;}return 0;}
function sim(m,h,s,f,t){f=f||1;var iS=h>=x.solS&&h<x.solE;
if(m===M.NABIJET)return Math.min(t||100,s+(C.chKwh*f*C.chEff/C.kap*100));
if(m===M.PRODAVAT)return Math.max(C.minSoc,s-(C.maxFeed/1000*f/C.dchEff/C.kap*100));
if(m===M.SETRIT)return s;
if(m===M.ZAKAZ)return Math.max(C.minSoc,s-C.socS*f);
if(m===M.NORMAL)return iS?Math.min(100,Math.max(C.minSoc,s+sG(h,f))):Math.max(C.minSoc,s-C.socN*f);
if(m===M.BAL)return iS?Math.min(100,s+(C.chKwh*f*C.chEff/C.kap*100)):s;return s;}
var ha=global.get("homeassistant.homeAssistant.states")||{};
var lB=(ha["input_datetime.last_pylontech_balanced"]||{}).state||"";
var dB=(lB&&lB!=="unknown")?(Date.now()-new Date(lB).getTime())/86400000:999;
var bNeed=dB>=C.balInt,bUsed=0,bSt=global.get("balancing_started_at")||0;
var bEl=bSt>0?(Date.now()-bSt)/3600000:0;
function R(s){return Math.round(s);}
function clamp(v){return Math.min(100,Math.max(C.minSoc,R(v)));}
function cM(off,pd,soc,f){f=f||1;var S=R(soc),lv=pd.levelBuy,sl=pd.sell;
if(C.manual!=="auto")return{mode:C.manual,reason:"Manuální režim, SOC "+S+"%"};
var canB=bNeed&&bUsed<C.balStop&&(off===0?bEl<C.balStop:true);
if(sl<=0&&!(canB&&x.sO[off]))return{mode:M.ZAKAZ,reason:"Záporná prodejní cena, SOC "+S+"%"};
if(canB&&x.sO[off]){var bh=(x.cH+off)%24,bk=x.fPH[bh]!==undefined?x.fPH[bh]:0;
if(bk<=0)bk=(x.fZ>0?x.fZ:x.rS)*sS(bh);if(bk>=C.balMinSol){bUsed++;
return{mode:M.BAL,reason:"Balancování baterie ("+bk.toFixed(1)+" kWh solární), SOC "+S+"%, "+R(dB)+" dní od posledního"};}}
if(x.cO[off]&&soc<x.tSoc){var eC=clamp(soc+(C.chKwh*f*C.chEff/C.kap*100));
return{mode:M.NABIJET,reason:"Nabíjení ze sítě na "+R(x.tSoc)+"%, SOC "+S+"→~"+eC+"%"};}
if(x.aCO[off]){var eA=clamp(soc+(C.chKwh*f*C.chEff/C.kap*100));
return{mode:M.NABIJET,reason:"Nabíjení (arbitráž pro hodinu "+x.aCO[off].targetHour+":00), SOC "+S+"→~"+eA+"%"};}
if(C.prodej&&soc>C.minSoc+C.nResPct){var rv=sl*C.dchEff,cb=C.amort;
if(x.viab.length>0){var s2=0;for(var i=0;i<x.viab.length;i++)s2+=x.viab[i].buy;cb=(s2/x.viab.length)/C.rtEff+C.amort;}
var eP=clamp(soc-(C.maxFeed/1000*f/C.dchEff/C.kap*100));
if((rv-cb>=C.minSell||x.aSO[off])&&eP>=C.minSoc+C.nResPct)
return{mode:M.PRODAVAT,reason:"Prodej do sítě (zisk "+R((rv-cb)*10)/10+" Kč/kWh), SOC "+S+"→~"+eP+"%"};}
if(soc<=C.minSoc)return{mode:M.SETRIT,reason:"Ochrana minimální SOC, SOC "+S+"% ≤ "+C.minSoc+"%"};
if(x.sO[off]){var hh=(x.cH+off)%24,sg=sG(hh,f),es=clamp(soc+sg);
var nibeN=(x.nibeK>0&&(x.fPH[hh]||0)>C.solOverKwh)?" (NIBE topí)":"";
if(sg<=0&&x.dO[off]&&soc>C.minSoc){var eV=clamp(soc-C.socN*f);
return{mode:M.NORMAL,reason:"Solární (nízký zisk) + vybíjení"+nibeN+", SOC "+S+"→~"+eV+"%"};}
if(sg>C.socN)return{mode:M.NORMAL,reason:"Solární hodina"+nibeN+", SOC "+S+"→~"+es+"%"};
if(lv>=C.DRAHA&&soc>C.minSoc)return{mode:M.NORMAL,reason:"Solární + drahá hodina (úroveň "+lv+")"+nibeN+", SOC "+S+"→~"+es+"%"};
if(x.bEx)return{mode:M.SETRIT,reason:"Solární (nízký zisk), šetřím baterii"+nibeN+", SOC "+S+"%"};
return{mode:M.NORMAL,reason:"Solární hodina"+nibeN+", SOC "+S+"→~"+es+"%"};}
if(x.dO[off]&&soc>C.minSoc){var eD=clamp(soc-C.socN*f);
var cn=lv>=C.DRAHA?"Drahá hodina":"Střední cena";
return{mode:M.NORMAL,reason:cn+" (úroveň "+lv+"), SOC "+S+"→~"+eD+"%"};}
if(lv>=C.DRAHA&&soc>C.minSoc){var eD2=clamp(soc-C.socN*f);
return{mode:M.NORMAL,reason:"Drahá hodina (úroveň "+lv+"), SOC "+S+"→~"+eD2+"%"};}
if(x.aS[off])return{mode:M.SETRIT,reason:"Šetřím pro dražší hodiny (úroveň "+lv+"), SOC "+S+"%"};
return{mode:M.SETRIT,reason:"Šetřím baterii (úroveň "+lv+"), SOC "+S+"%"};}
var nm={normal:"Normální provoz",setrit:"Šetřit baterii",nabijet_ze_site:"Nabíjet ze sítě",prodavat:"Prodávat do sítě",zakaz_pretoku:"Zákaz přetoků","Balancování":"Balancování baterie"};
var plan=[],sm=x.cSoc;
for(var pi=0;pi<C.hor;pi++){var ph=(x.cH+pi)%24,nd=(x.cH+pi)>=24,pd=hp[pi],hf=pi===0?x.fFrac:1;
var r=cM(pi,pd,sm,hf);sm=sim(r.mode,ph,sm,hf,x.tSoc);
plan.push({hour:ph,offset:pi,mode:r.mode,modeCZ:nm[r.mode]||r.mode,reason:r.reason,
priceLevel:pd.levelBuy,priceBuy:pd.buy,priceSell:pd.sell,simulatedSoc:Math.round(sm),isNextDay:nd,
isChargingHour:x.cO[pi]||false,isSolarHour:x.sO[pi]||false,isDischargeHour:x.dO[pi]||false,
isArbitrageCharge:!!x.aCO[pi],isArbitrageSell:!!x.aSO[pi],isBalancovani:r.mode===M.BAL});}
x.plan=plan;
node.status({fill:"green",shape:"dot",text:"Plan "+plan.length+"h SOC:"+x.cSoc+"→"+Math.round(sm)+"%"});
return msg;

// [5/5] Výstup plánu — msg.payload pro uložení
var x=msg.ctx, C=x.C, p=x.plan;
var cS=0,cN=0,cNb=0,cP=0,cB=0;
for(var i=0;i<p.length;i++){var m=p[i].mode;if(m==="setrit")cS++;else if(m==="normal")cN++;else if(m==="nabijet_ze_site")cNb++;else if(m==="prodavat")cP++;else if(m==="Balancování")cB++;}
var cur=p.length>0?p[0].mode:"normal", sTgt=C.minSoc;
if(cur==="prodavat"&&p.length>0)sTgt=p[0].simulatedSoc;
msg.payload={
