    status:{soc:x.cSoc,remainingSolar:x.rS,forecastZitra:x.fZ,forecastDnes:x.fc.dnes||0,
        prodejEnabled:C.prodej,blokaceVybijeni:C.blokace,blokaceText:x.bTxt},
    generatedAt:x.now.toISOString()};
var cl={normal:"green",setrit:"yellow",nabijet_ze_site:"blue",prodavat:"red",zakaz_pretoku:"purple","Balancování":"cyan"};
node.status({fill:cl[cur]||"grey",shape:"dot",text:"Š:"+cS+" N:"+cN+" Nab:"+cNb+" P:"+cP+" B:"+cB+" SOC:"+x.cSoc+"%"});
return msg;
